/// canonicalization — `--squash` is already parsed into a
/// `SquashSpec` by clap). The `--log` path lives on `Context`,
/// not here.
#[derive(Debug)]
pub struct FinalizeParams {
    pub repo: PathBuf,
    pub squash: Option<SquashSpec>,
    pub delay_secs: f64,
    pub bookmark: Option<String>,
    pub push: bool,
    pub detach: bool,
    pub exec: bool,
}

impl TryFrom<&FinalizeArgs> for FinalizeParams {
    type Error = String;

    /// Derive `push`/`bookmark` from `--push` and canonicalize
    /// `--repo` (so the detached child resolves it regardless of
    /// cwd); `--squash` was already parsed by clap.
    fn try_from(a: &FinalizeArgs) -> Result<Self, String> {
        let repo = std::fs::canonicalize(&a.repo)
            .map_err(|e| format!("cannot resolve repo path '{}': {e}", a.repo.display()))?;
        Ok(FinalizeParams {
            repo,
            squash: a.squash.value.clone(),
            delay_secs: a.delay,
            bookmark: a.push.clone(),
            push: a.push.is_some(),
            detach: a.detach,
            exec: a.exec,
        })
    }
}

/// `COMMITS` (`pos_rev` / `pos_count`), `--revision` / `--commits`
/// (`revision` / `limit`), `--max-fixes`, `--repo`, `--other-repo`,
/// `--id-len`, `--title`, `--fallback`, `--no-dry-run`,
/// `--add-missing`.
pub struct FixDescParams {
    pub pos_rev: Option<String>,
    pub pos_count: Option<usize>,
    pub revision: String,
    pub limit: Option<usize>,
    pub max_fixes: Option<usize>,
    pub repo: PathBuf,
    pub other_repo: Option<PathBuf>,
    pub id_len: usize,
    pub title: Option<String>,
    pub fallback: Option<String>,
    pub no_dry_run: bool,
    pub add_missing: bool,
}

impl From<&FixDescArgs> for FixDescParams {
    /// Convert clap-derived `FixDescArgs` into the flat
    /// `FixDescParams` (total — every field copies straight over).
    fn from(a: &FixDescArgs) -> Self {
        Self {
            pos_rev: a.pos_rev.clone(),
            pos_count: a.pos_count,
            revision: a.revision.clone(),
            limit: a.limit,
            max_fixes: a.max_fixes,
            repo: a.repo.clone(),
            other_repo: a.other_repo.clone(),
            id_len: a.id_len,
            title: a.title.clone(),
            fallback: a.fallback.clone(),
            no_dry_run: a.no_dry_run,
            add_missing: a.add_missing,
        }
    }
}

