45	/// Print the short change ID of each commit in the resolved range.
46	///
47	/// `_ctx` is unused (chid has no user-config or `--log` consumer);
48	/// it's present for the uniform subcommand-layer signature.
49	pub fn chid(_ctx: &Context, params: &ChidParams) -> Result<(), Box<dyn std::error::Error>> {
50	    debug!("chid: enter");
51	    let c = &params.common;
52	    common::for_each_repo(&c.repos, &c.header, |workspace, repo| {
53	        let (ids, _) = common::collect_ids(
54	            workspace,
55	            repo,
56	            &c.spec.rev,
57	            c.spec.desc_count,
58	            c.spec.anc_count,
59	        )?;
60	        for commit_id in &ids {
61	            let commit = repo.store().get_commit(commit_id)?;
62	            info!("{}", common::format_chid(&commit));
63	        }
64	        Ok(())
65	    })?;
66	    debug!("chid: exit");
67	    Ok(())
68	}
