26	/// Result of parsing positional `..` notation.
27	///
28	/// Counts are `Some(0)` for closed sides and `None` for open (dotted) sides.
29	/// Open sides become unlimited unless a positional count is applied later.
30	#[derive(Debug, Clone, PartialEq, Eq)]
31	pub struct DotSpec {
32	    /// The bare revision (without `..`).
33	    pub rev: String,
34	    /// Descendant count: `None` = open (dotted), `Some(0)` = closed.
35	    pub desc_count: Option<usize>,
36	    /// Ancestor count: `None` = open (dotted), `Some(0)` = closed.
37	    pub anc_count: Option<usize>,
38	}
39	
40	/// Parse a positional REV string for `..` notation.
41	///
42	/// Returns the bare revision with open/closed counts per side.
43	/// `None` means the side had dots (open for expansion);
44	/// `Some(0)` means no dots on that side (closed).
45	/// Actual counts are applied later from positional args.
46	pub fn parse_dot_rev(rev: &str) -> DotSpec {
47	    if let Some(inner) = rev.strip_prefix("..").and_then(|s| s.strip_suffix("..")) {
48	        DotSpec {
49	            rev: inner.to_string(),
50	            desc_count: None,
51	            anc_count: None,
52	        }
53	    } else if let Some(inner) = rev.strip_prefix("..") {
54	        DotSpec {
55	            rev: inner.to_string(),
56	            desc_count: None,
57	            anc_count: Some(0),
58	        }
59	    } else if let Some(inner) = rev.strip_suffix("..") {
60	        DotSpec {
61	            rev: inner.to_string(),
62	            desc_count: Some(0),
63	            anc_count: None,
64	        }
65	    } else {
66	        DotSpec {
67	            rev: rev.to_string(),
68	            desc_count: Some(0),
69	            anc_count: Some(0),
70	        }
71	    }
72	}
