74	/// Resolve positional and flag args into a `DotSpec` ready for `collect_ids`.
75	///
76	/// Handles: dot notation parsing, flag vs positional precedence,
77	/// count-means-total semantics (subtracts 1 for anchor).
78	pub fn resolve_spec(
79	    pos_rev: Option<&str>,
80	    pos_count: Option<usize>,
81	    flag_rev: &str,
82	    flag_limit: Option<usize>,
83	    default_rev: &str,
84	) -> DotSpec {
85	    let flag_rev_set = flag_rev != default_rev;
86	    let rev_str = if flag_rev_set {
87	        flag_rev
88	    } else {
89	        pos_rev.unwrap_or(default_rev) // OK: positional absent → fall back to CLI default
90	    };
91	    let mut spec = parse_dot_rev(rev_str);
92	
93	    let count = if flag_limit.is_some() {
94	        flag_limit
95	    } else {
96	        pos_count
97	    };
98	
99	    if let Some(c) = count {
100	        let n = c.saturating_sub(1);
101	        let both_open = spec.desc_count.is_none() && spec.anc_count.is_none();
102	        if both_open {
103	            // Split budget across both sides: ancestors get the extra
104	            let desc_n = n / 2;
105	            let anc_n = n - desc_n;
106	            spec.desc_count = Some(desc_n);
107	            spec.anc_count = Some(anc_n);
108	        } else {
109	            if spec.desc_count.is_none() {
110	                spec.desc_count = Some(n);
111	            }
112	            if spec.anc_count.is_none() {
113	                spec.anc_count = Some(n);
114	            }
115	            // bare `x 5` → treat as `x.. 5` (ancestors)
116	            if spec.desc_count == Some(0) && spec.anc_count == Some(0) {
117	                spec.anc_count = Some(n);
118	            }
119	        }
120	    }
121	
122	    spec
123	}
