125	/// Run a shell command. Returns stdout on success.
126	///
127	/// Logs the command at `debug!` and the process streams as follows:
128	/// - **stderr at `debug!`** on success — jj's chatter (`Moved 1 bookmarks
129	///   to …`, `Rebased N commits`, `Nothing changed.`) is hidden by default
130	///   and surfaced with `-v`. The debug formatter indents each line two
131	///   spaces so subprocess output sits visually under the caller's own
132	///   `info!` line in `-v` mode.
133	/// - **stdout at `debug!`** — callers usually consume stdout as data
134	///   (bookmark lists, commit IDs, etc.), and `info!` would flood the user
135	///   with machine-readable output they didn't ask for.
136	/// - **Failures propagate as `Err`** carrying the stderr; the caller's
137	///   error handler (`main::run_command`) surfaces it at `error!`.
138	pub fn run(cmd: &str, args: &[&str], cwd: &Path) -> Result<String, Box<dyn std::error::Error>> {
139	    let args_str = args.join(" ");
140	    debug!("$ {cmd} {args_str}");
141	    trace!("cwd: {}", cwd.display());
142	    let output = std::process::Command::new(cmd)
143	        .args(args)
144	        .current_dir(cwd)
145	        .output()
146	        .map_err(|e| format!("failed to run {cmd}: {e}"))?;
147	    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
148	    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
149	    if !stdout.is_empty() {
150	        debug!("{stdout}");
151	    }
152	    if !output.status.success() {
153	        return Err(format!("{cmd} {args_str} failed: {stderr}").into());
154	    }
155	    if !stderr.is_empty() {
156	        debug!("{stderr}");
157	    }
158	    Ok(stdout)
159	}
